INSERT INTO `serialized_object` VALUES
(31,'MSF Patient Encounters SQL Dataset','Patient encounter records with provider information and MSF identifiers. One row per encounter.','org.openmrs.module.reporting.dataset.definition.DataSetDefinition','org.openmrs.module.reporting.dataset.definition.SqlDataSetDefinition','org.openmrs.module.reporting.serializer.ReportingSerializer','<org.openmrs.module.reporting.dataset.definition.SqlDataSetDefinition id=\"1\" uuid=\"35e338f2-6011-4f50-b2dc-f06a80e1a99c\" retired=\"false\">\n  <name>MSF Patient Encounters SQL Dataset</name>\n  <description>Patient encounter records with provider information and MSF identifiers. One row per encounter.</description>\n  <creator id=\"2\" uuid=\"82f18b44-6814-11e8-923f-e9a88dcb533f\"/>\n  <dateCreated id=\"3\">2026-03-02 14:37:37 UTC</dateCreated>\n  <changedBy reference=\"2\"/>\n  <dateChanged id=\"4\">2026-03-02 14:37:57 UTC</dateChanged>\n  <parameters id=\"5\">\n    <org.openmrs.module.reporting.evaluation.parameter.Parameter id=\"6\">\n      <name>startDate</name>\n      <label>startDate</label>\n      <type>java.util.Date</type>\n      <required>true</required>\n    </org.openmrs.module.reporting.evaluation.parameter.Parameter>\n    <org.openmrs.module.reporting.evaluation.parameter.Parameter id=\"7\">\n      <name>endDate</name>\n      <label>endDate</label>\n      <type>java.util.Date</type>\n      <required>true</required>\n    </org.openmrs.module.reporting.evaluation.parameter.Parameter>\n  </parameters>\n  <id>31</id>\n  <sqlQuery>SELECT&#xd;\n    COALESCE(pr.name, u.username) AS &apos;Provider name&apos;,&#xd;\n&#xd;\n    msf_id.identifier AS &apos;MSF ID&apos;,&#xd;\n&#xd;\n    legacy_msf_id.identifier AS &apos;Legacy MSF ID&apos;,&#xd;\n&#xd;\n    DATE_FORMAT(v.date_started, &apos;%Y-%m-%d&apos;) AS &apos;Visit date&apos;,&#xd;\n&#xd;\n    report_visit_type.name AS &apos;Visit Type&apos;,&#xd;\n&#xd;\n    l.name AS &apos;Location&apos;,&#xd;\n&#xd;\n    DATE_FORMAT(e.encounter_datetime, &apos;%Y-%m-%d %H:%i&apos;) AS &apos;Encounter date/time&apos;,&#xd;\n&#xd;\n    et.name AS &apos;Encounter type&apos;,&#xd;\n&#xd;\n    f.name AS &apos;Form name&apos;&#xd;\n&#xd;\nFROM encounter e&#xd;\n&#xd;\nINNER JOIN users u &#xd;\n    ON e.creator = u.user_id&#xd;\n&#xd;\nINNER JOIN visit v &#xd;\n    ON e.visit_id = v.visit_id&#xd;\n&#xd;\nINNER JOIN encounter_type et&#xd;\n    ON e.encounter_type = et.encounter_type_id&#xd;\n&#xd;\nINNER JOIN location l&#xd;\n    ON e.location_id = l.location_id&#xd;\n&#xd;\nLEFT JOIN (&#xd;\n        SELECT vt.name, vt.visit_type_id, vst.visit_id&#xd;\n        FROM visit_type vt&#xd;\n        INNER JOIN visit vst ON vt.visit_type_id = vst.visit_type_id&#xd;\n        ORDER BY vt.date_created DESC&#xd;\n) report_visit_type ON e.visit_id = report_visit_type.visit_id&#xd;\n&#xd;\nLEFT JOIN encounter_provider ep&#xd;\n    ON e.encounter_id = ep.encounter_id&#xd;\n    AND ep.voided = 0&#xd;\n&#xd;\nLEFT JOIN provider pr&#xd;\n    ON ep.provider_id = pr.provider_id&#xd;\n&#xd;\nLEFT JOIN patient_identifier msf_id&#xd;\n    ON e.patient_id = msf_id.patient_id&#xd;\n    AND msf_id.preferred = 1&#xd;\n    AND msf_id.voided = 0&#xd;\n&#xd;\nLEFT JOIN (&#xd;\n        SELECT pi.patient_id, pi.identifier&#xd;\n        FROM patient_identifier pi&#xd;\n        INNER JOIN patient_identifier_type pit ON pi.identifier_type = pit.patient_identifier_type_id&#xd;\n        WHERE pit.name LIKE &apos;%Legacy MSF ID%&apos;&#xd;\n        ORDER BY pi.date_created DESC&#xd;\n) legacy_msf_id ON e.patient_id = legacy_msf_id.patient_id&#xd;\n&#xd;\nLEFT JOIN form f&#xd;\n    ON e.form_id = f.form_id&#xd;\n&#xd;\nWHERE&#xd;\n    e.encounter_datetime BETWEEN :startDate AND :endDate&#xd;\n    AND e.voided = 0&#xd;\n&#xd;\nORDER BY&#xd;\n    e.encounter_datetime DESC;</sqlQuery>\n</org.openmrs.module.reporting.dataset.definition.SqlDataSetDefinition>','2026-03-02 14:37:37',1,'2026-03-02 14:37:57',1,0,NULL,NULL,NULL,'35e338f2-6011-4f50-b2dc-f06a80e1a99c'),
(32,'MSF Patient Encounter Report','Report showing Patient encounter records with provider information and MSF identifiers. One row per encounter.','org.openmrs.module.reporting.report.definition.ReportDefinition','org.openmrs.module.reporting.report.definition.ReportDefinition','org.openmrs.module.reporting.serializer.ReportingSerializer','<org.openmrs.module.reporting.report.definition.ReportDefinition id=\"1\" uuid=\"e3019e58-017b-4f4c-93b9-636cc3a30b7b\" retired=\"false\">\n  <name>MSF Patient Encounter Report</name>\n  <description>Report showing Patient encounter records with provider information and MSF identifiers. One row per encounter.</description>\n  <creator id=\"2\" uuid=\"82f18b44-6814-11e8-923f-e9a88dcb533f\"/>\n  <dateCreated id=\"3\">2026-03-02 14:39:19 UTC</dateCreated>\n  <changedBy reference=\"2\"/>\n  <dateChanged id=\"4\">2026-03-02 14:40:26 UTC</dateChanged>\n  <parameters id=\"5\">\n    <org.openmrs.module.reporting.evaluation.parameter.Parameter id=\"6\">\n      <name>startDate</name>\n      <label>Start Date</label>\n      <type>java.util.Date</type>\n      <required>true</required>\n    </org.openmrs.module.reporting.evaluation.parameter.Parameter>\n    <org.openmrs.module.reporting.evaluation.parameter.Parameter id=\"7\">\n      <name>endDate</name>\n      <label>End Date</label>\n      <type>java.util.Date</type>\n      <required>true</required>\n    </org.openmrs.module.reporting.evaluation.parameter.Parameter>\n  </parameters>\n  <id>32</id>\n  <dataSetDefinitions class=\"linked-hash-map\" id=\"8\">\n    <entry>\n      <string>MSF-Patient-Encounters-SQL-Dataset</string>\n      <org.openmrs.module.reporting.evaluation.parameter.Mapped id=\"9\">\n        <parameterizable class=\"org.openmrs.module.reporting.dataset.definition.SqlDataSetDefinition\" id=\"10\" uuid=\"35e338f2-6011-4f50-b2dc-f06a80e1a99c\"/>\n        <parameterMappings id=\"11\">\n          <entry>\n            <string>endDate</string>\n            <string>${endDate}</string>\n          </entry>\n          <entry>\n            <string>startDate</string>\n            <string>${startDate}</string>\n          </entry>\n        </parameterMappings>\n      </org.openmrs.module.reporting.evaluation.parameter.Mapped>\n    </entry>\n  </dataSetDefinitions>\n</org.openmrs.module.reporting.report.definition.ReportDefinition>','2026-03-02 14:39:19',1,'2026-03-02 14:40:26',1,0,NULL,NULL,NULL,'e3019e58-017b-4f4c-93b9-636cc3a30b7b');